(function(g){function s(v){return typeof v==="number"&&isFinite(v)}function r(v,m,M){return Math.max(m,Math.min(M,v))}class uPlot{constructor(o,d,t){this.opts=o||{};this.data=d||[[]];this.target=t;this.root=document.createElement("div");this.root.className="uplot";this.target.innerHTML="";this.target.appendChild(this.root);this.width=0;this.height=0;this.setSize({width:this.target.clientWidth||240,height:this.target.clientHeight||120})}destroy(){if(this.root&&this.root.parentNode){this.root.parentNode.removeChild(this.root)}}setData(d){this.data=d||[[]];this.render()}setSize(size){this.width=Math.max(40,Math.floor(size.width||240));this.height=Math.max(30,Math.floor(size.height||120));this.render()}render(){const x=this.data[0]||[];const series=(this.opts.series||[]).slice(1);const yMin=((this.opts.scales||{}).y||{}).min??0;const yMax=((this.opts.scales||{}).y||{}).max??100;this.root.innerHTML="";if(!Array.isArray(x)||x.length<2||!series.length){const empty=document.createElement("div");empty.className="uplot-empty";empty.textContent="no data yet";this.root.appendChild(empty);return}const ns="http://www.w3.org/2000/svg";const svg=document.createElementNS(ns,"svg");svg.setAttribute("viewBox",`0 0 ${this.width} ${this.height}`);svg.setAttribute("preserveAspectRatio","none");const pad=4;const drawWidth=Math.max(1,this.width-pad*2);const drawHeight=Math.max(1,this.height-pad*2);series.forEach((serie,idx)=>{const values=this.data[idx+1]||[];const pts=[];for(let i=0;i<x.length;i+=1){const val=values[i];if(!s(val)){continue}const px=pad+(i/(x.length-1))*drawWidth;const py=pad+(1-r((val-yMin)/(yMax-yMin||1),0,1))*drawHeight;pts.push(`${px},${py}`)}if(pts.length<2){return}const poly=document.createElementNS(ns,"polyline");poly.setAttribute("fill","none");poly.setAttribute("stroke",serie.stroke||"#fff");poly.setAttribute("stroke-width",String(serie.width||2));poly.setAttribute("stroke-linecap","round");poly.setAttribute("stroke-linejoin","round");poly.setAttribute("points",pts.join(" "));svg.appendChild(poly)});this.root.appendChild(svg)}}g.uPlot=uPlot})(window);
